import{_ as t,o as a,c as i,ae as n}from"./chunks/framework.BuvKvcPh.js";const s="/Furniture-Designer/images/manufacturing-fr.png",g=JSON.parse('{"title":"Fabrication & Optimisation","description":"","frontmatter":{},"headers":[],"relativePath":"fr/manufacturing.md","filePath":"fr/manufacturing.md"}'),r={name:"fr/manufacturing.md"};function o(l,e,u,c,p,d){return a(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="fabrication-optimisation" tabindex="-1">Fabrication &amp; Optimisation <a class="header-anchor" href="#fabrication-optimisation" aria-label="Permalink to &quot;Fabrication &amp; Optimisation&quot;">​</a></h1><p>Une fois le plan 3D abouti, passez à la production en scierie.</p><p><img src="'+s+'" alt="Interface Fabrication"></p><h2 id="la-liste-de-debit-cut-list" tabindex="-1">La Liste de Débit (Cut List) <a class="header-anchor" href="#la-liste-de-debit-cut-list" aria-label="Permalink to &quot;La Liste de Débit (Cut List)&quot;">​</a></h2><p>La liste de coupe dresse l&#39;inventaire plat de toutes les planches de bois individuelles requises pour assembler le meuble.</p><ul><li><strong>Déductions d&#39;épaisseur</strong> : L&#39;algorithme gère de façon inhérente les intersections (les étagères s&#39;arrêtent naturellement contre les montants verticaux). Les dimensions listées ici sont définitives et exactes.</li><li><strong>Regroupement</strong> : Les planches identiques sont groupées par quantité.</li><li><strong>Surface Totale</strong> : Observez la surface exacte (en m²) de matière première consommée pour vous aider à deviser vos achats.</li><li><strong>Hardware</strong> : Anticipez le nombre de tourillons en bois nécessaires à l&#39;assemblage complet.</li><li><strong>Exportation</strong> : Exportez cette vue sous forme de Plan PDF très lisible, conçu pour être imprimé et apporté à l&#39;établi.</li></ul><h2 id="le-plan-de-coupe-cut-plan-packer" tabindex="-1">Le Plan de Coupe (Cut Plan Packer) <a class="header-anchor" href="#le-plan-de-coupe-cut-plan-packer" aria-label="Permalink to &quot;Le Plan de Coupe (Cut Plan Packer)&quot;">​</a></h2><p>Plutôt que d&#39;essayer de résoudre vous-même comment tailler vos 12 planches dans un grand panneau standard du commerce, le <strong>Panificateur</strong> agit comme un solveur (2D Bin Packing).</p><h3 id="fonctionnalites-de-l-optimiseur" tabindex="-1">Fonctionnalités de l&#39;Optimiseur <a class="header-anchor" href="#fonctionnalites-de-l-optimiseur" aria-label="Permalink to &quot;Fonctionnalités de l&#39;Optimiseur&quot;">​</a></h3><ul><li><strong>Taille de lame (Kerf)</strong> : Renseignez l&#39;épaisseur de votre lame de scie circulaire (ex: 3mm). Le moteur de packing respecte scrupuleusement cette zone perdue entre chaque découpe.</li><li><strong>Panneaux Commerciaux Mixtes</strong> : Acheter de petites plaques peut parfois s&#39;avérer moins cher que réduire un immense panneau standard en copeaux. Vous pouvez configurer plusieurs tailles de panneaux (Ex: Plaque 2440x1220 à 45€, et Plaque 1220x600 à 15€).</li><li><strong>Algorithme &quot;Smart Mix&quot;</strong> : L&#39;algorithme calcule les combinaisons et vous propose la combinaison de panneaux absolue <strong>la moins chère</strong> de votre panier.</li><li><strong>Rotations</strong> : Le moteur tente des rotations intelligentes pour maximiser la densité d&#39;agencement.</li></ul><p><em>Note: Toutes les pièces qui physiquement refusent de rentrer dans la plus grande plaque que vous avez saisie sont listées en erreur afin de vous avertir.</em></p>',11)])])}const f=t(r,[["render",o]]);export{g as __pageData,f as default};
